def seq_ratio(a,b):
    return difflib.SequenceMatcher(None, a, b).ratio()

def lcs_len(a,b):
    # simple DP
    n,m = len(a), len(b)
    # we'll optimize memory
    dp_prev = [0]*(m+1)
    for i in range(1, n+1):
        dp_curr = [0]*(m+1)
        ca = a[i-1]
        for j in range(1, m+1):
            if ca == b[j-1]:
                dp_curr[j] = dp_prev[j-1] + 1
            else:
                dp_curr[j] = dp_prev[j] if dp_prev[j] >= dp_curr[j-1] else dp_curr[j-1]
        dp_prev = dp_curr
    return dp_prev[m]

def lcs_ratio(a,b, norm='max'):
    L = lcs_len(a,b)
    if norm == 'max':
        return L / max(len(a), len(b))
    elif norm == 'min':
        return L / min(len(a), len(b))
    else:
        return 2*L/(len(a)+len(b))

